      const remainingAvatars = avatars.length - displayedAvatars.length;
      const progress = row.original.progress;
      const bgColor =
        progress < 30
          ? "danger"
          : progress < 50
          ? "warning"
          : progress > 50 && progress < 90
          ? "info"
          : "primary";
      return (
        <AvatarGroup>
          {displayedAvatars.map((avatar, index) => (
