import { useContext, ReactNode } from "react";
import { AccordionContext, useAccordionButton, Nav } from "react-bootstrap";
import Link from "next/link";

interface CustomToggleProps {
  children: ReactNode;
  eventKey: string;
  className?: string;
  href?: string;
  dataBsTarget?: string;
  ariaControls?: string;
  icon?: ReactNode;
  callback?: (eventKey: string) => void;
}

export default function CustomToggle({
  children,
  eventKey,
  icon,
  callback,
}: CustomToggleProps) {
  const { activeEventKey } = useContext(AccordionContext);
  const decoratedOnClick = useAccordionButton(
    eventKey,
    () => callback && callback(eventKey)
  );

  const isCurrentEventKey = activeEventKey === eventKey;
  return (
    <Nav.Item as="li" className="dropdown">
      <Nav.Link
        href="#"
        onClick={decoratedOnClick}
        data-bs-toggle="dropdown"
        aria-expanded={isCurrentEventKey ? true : false}
        className="dropdown-toggle"
      >
        <span className="nav-icon">{icon}</span>
        <span className="text">{children}</span>
      </Nav.Link>
    </Nav.Item>
  );
}

export function CustomToggleLevel2({
  children,
  eventKey,
  className = "nav-link",
  href = "#",
  dataBsTarget = "",
  ariaControls = "",
}: CustomToggleProps) {
  const { activeEventKey } = useContext(AccordionContext);
  const decoratedOnClick = useAccordionButton(eventKey);
  const isCurrentEventKey = activeEventKey === eventKey;

  return (
    <Link
      href={href}
      className={className}
      onClick={decoratedOnClick}
      data-bs-toggle="collapse"
      data-bs-target={dataBsTarget}
      aria-expanded={isCurrentEventKey}
      aria-controls={ariaControls}
    >
      <span>{children}</span>
    </Link>
  );
}"}, {"path": "src/components/TablePagination.tsx", "content": "//import node modules libraries
import React from "react";
import { Navbar, Pagination } from "react-bootstrap";
import { ChevronLeft, ChevronRight } from "react-feather";
import { Table as ReactTable, RowData } from "@tanstack/react-table";

interface TablePaginationProps<TData extends RowData> {
  table: ReactTable<TData>;
  hasIcon?: boolean;
}

const TablePagination = <TData extends RowData>({
  table,
  hasIcon,
}: TablePaginationProps<TData>) => {
  const pageSize = table.options.state.pagination?.pageSize ?? 10;
  const pageIndex = table.options.state.pagination?.pageIndex ?? 0;
  const pageCount = table.getPageCount();
  const totalRows = table.getFilteredRowModel().rows.length;

  return (
    <div className="border-top d-md-flex justify-content-between align-items-center p-3">
      <div>
        Showing {pageIndex * pageSize + 1} to{" "}
        {Math.min((pageIndex + 1) * pageSize, totalRows)} of {totalRows} entries
      </div>
      <Navbar className="mt-2 mt-md-0">
        <Pagination className="mb-0">
          {/* Previous Button */}
          <Pagination.Item
            disabled={!table.getCanPreviousPage()}
            onClick={() => table.previousPage()}
          >
            {hasIcon ? <ChevronLeft className="icon-xxs" /> : "Previous"}
          </Pagination.Item>

          {/* Page Numbers */}
          {Array.from(Array(pageCount).keys()).map((page) => (
            <Pagination.Item
              key={page}
              active={pageIndex === page}
              onClick={() => table.setPageIndex(page)}
            >
              {page + 1}
            </Pagination.Item>
          ))}

          {/* Next Button */}
          <Pagination.Item
            disabled={!table.getCanNextPage()}
            onClick={() => table.nextPage()}
          >
            {hasIcon ? <ChevronRight className="icon-xxs" /> : "Next"}
          </Pagination.Item>
        </Pagination>
      </Navbar>
    </div>
  );
};

export default TablePagination;"}, {"path": "src/components/TanstackTable.tsx", "content": ""use client";
// import node module libraries
import React, { Fragment, useState } from "react";
import { Table } from "react-bootstrap";
import { ChevronUp, ChevronDown } from "react-feather";
import {
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  ColumnDef,
  SortingState,
  RowSelectionState,
} from "@tanstack/react-table";

// import custom components
import GlobalFilter from "./GlobalFilter";
import TablePagination from "./TablePagination";

interface TanstackTableProps<TData> {
  data: TData[];
  columns: ColumnDef<TData, unknown>[];
  filter?: boolean;
  pagination?: boolean;
  filterPlaceholder?: string;
  header?: boolean;
  onRowClick?: (row: TData) => void;
  showIcon?: boolean;
  className?: string;
  tableClass?: string;
  tdClass?: string;
  isSortable?: boolean;
}

function TanstackTable<TData>({
  data,
  columns,
  filter = false,
  pagination = false,
  filterPlaceholder,
  header = true,
  onRowClick,
  showIcon,
  className,
  tableClass,
  tdClass,
  isSortable = false,
  ...props
}: TanstackTableProps<TData>) {
  const [filtering, setFiltering] = useState<string>("");
  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});
  const [sorting, setSorting] = useState<SortingState>([]);

  const table = useReactTable<TData>({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    enableSorting: isSortable,
    getPaginationRowModel: getPaginationRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    state: {
      globalFilter: filtering,
      rowSelection: rowSelection,
      sorting,
    },
    onSortingChange: setSorting,
    getSortedRowModel: getSortedRowModel(),
    onRowSelectionChange: setRowSelection,
    enableRowSelection: true,
    onGlobalFilterChange: setFiltering,
    debugTable: false,
  });

  const hasTableData = Array.isArray(data) && data?.length > 0;

  if (!hasTableData) {
    return (
      <div className="text-center p-5">
        <p className="text-muted mb-0">No data available</p>
      </div>
    );
  }
  return (
    <Fragment>
      {filter && (
        <GlobalFilter
          filtering={filtering}
          setFiltering={setFiltering}
          placeholder={filterPlaceholder}
          table={table}
        />
      )}

      <div className={className ? className : "table-responsive table-card"}>
        <Table
          className={
            tableClass ? tableClass : "text-nowrap table-centered mt-0"
          }
          style={{ width: "100%" }}
          id="example"
          {...props}
        >
          {header && (
            <thead className="bg-light">
              {table.getHeaderGroups().map((headerGroup) => (
                <tr key={headerGroup.id}>
                  {headerGroup.headers.map((header) => (
                    <th
                      key={header.id}
                      onClick={header.column.getToggleSortingHandler()}
                      colSpan={header.colSpan}
                    >
                      {header.isPlaceholder ? null : (
                        <div
                          {...{
                            className: header.column.getCanSort()
                              ? "sorting"
                              : "",
                          }}
                        >
                          {flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                          {{
                            asc: <ChevronUp size={16} />,
                            desc: <ChevronDown size={16} />,
                          }[header.column.getIsSorted() as string] ?? null}
                        </div>
                      )}
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
          )}

          <tbody>
            {table.getRowModel().rows.map((row) => (
              <tr
                key={row.id}
                onClick={
                  onRowClick ? () => onRowClick(row.original) : undefined
                }
                style={onRowClick ? { cursor: "pointer" } : undefined}
              >
                {row.getVisibleCells().map((cell) => (
                  <td key={cell.id} className={tdClass}>
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </Table>
      </div>

      {pagination && <TablePagination table={table} hasIcon={showIcon} />}
    </Fragment>
  );
}

