        startup: true,
        enterprise: true,
      },
      {
        name: "Integrations",
        free: true,
        startup: true,
        enterprise: true,
      },
      {
        name: "Mainline AI",
        free: null,
        startup: true,
        enterprise: true,
      },
      {
        name: "Admin roles",
        free: null,
        startup: null,
        enterprise: true,
      },
      {
        name: "Audit log",
        free: null,
        startup: null,
        enterprise: true,
      },
    ],
  },
  {
    category: "Support",
