                          : "max-h-0 opacity-0",
                      )}
                    >
                      <div className="bg-muted/50 space-y-3 rounded-lg p-4">
                        {link.dropdownItems.map((item) => (
                          <Link
                            key={item.title}
                            href={item.href}
                            className="group hover:bg-accent block rounded-md p-2 transition-colors"
                            onClick={() => {
                              setIsMenuOpen(false);
